/* =====================================================
   P5.JS — BANNER HOME
   El video principal se reproduce dentro de un canvas P5.js
   para que el banner del inicio sea un bloque programado.
===================================================== */
new p5(function(p) {
  var heroVideo;
  var container;

  p.setup = function() {
    container = document.getElementById('hero-canvas-container');
    if (!container) return;

    var w = Math.max(1, container.offsetWidth);
    var h = Math.max(1, container.offsetHeight);
    var cnv = p.createCanvas(w, h);
    cnv.parent('hero-canvas-container');

    heroVideo = p.createVideo(['images/banner-home.mp4']);
    heroVideo.elt.muted = true;
    heroVideo.elt.defaultMuted = true;
    heroVideo.elt.playsInline = true;
    heroVideo.elt.setAttribute('muted', '');
    heroVideo.elt.setAttribute('playsinline', '');
    heroVideo.volume(0);
    heroVideo.hide();
    heroVideo.loop();
    p.noStroke();
  };

  p.draw = function() {
    p.background(7, 7, 14);
    if (!heroVideo || !heroVideo.elt || heroVideo.elt.readyState < 2) return;

    var vw = heroVideo.elt.videoWidth || 1280;
    var vh = heroVideo.elt.videoHeight || 720;
    var scale = Math.max(p.width / vw, p.height / vh);
    var dw = vw * scale;
    var dh = vh * scale;
    var dx = (p.width - dw) * 0.5;
    var dy = (p.height - dh) * 0.5;

    p.image(heroVideo, dx, dy, dw, dh);
  };

  p.windowResized = function() {
    if (!container) container = document.getElementById('hero-canvas-container');
    if (!container) return;
    p.resizeCanvas(Math.max(1, container.offsetWidth), Math.max(1, container.offsetHeight));
  };

  p.mousePressed = function() {
    if (heroVideo && heroVideo.elt.paused) heroVideo.loop();
  };

  p.touchStarted = function() {
    if (heroVideo && heroVideo.elt.paused) heroVideo.loop();
  };
});

/* NAV */
window.addEventListener('scroll', function() {
  document.getElementById('nav').classList.toggle('scrolled', window.scrollY > 60);
}, { passive: true });

/* NAV TOGGLE — menú mobile */
(function() {
  var toggle = document.getElementById('nav-toggle');
  var links  = document.querySelector('.nav-links');
  if (!toggle || !links) return;
  function cerrar() {
    links.classList.remove('open');
    toggle.setAttribute('aria-expanded', 'false');
  }
  toggle.addEventListener('click', function() {
    var abierto = links.classList.toggle('open');
    toggle.setAttribute('aria-expanded', abierto ? 'true' : 'false');
  });
  links.querySelectorAll('a').forEach(function(a) {
    a.addEventListener('click', cerrar);
  });
})();

/* REVEAL ON SCROLL */
var revealObs = new IntersectionObserver(function(entries) {
  entries.forEach(function(e) {
    if (e.isIntersecting) { e.target.classList.add('vis'); revealObs.unobserve(e.target); }
  });
}, { threshold: 0.12 });
document.querySelectorAll('.reveal').forEach(function(el) { revealObs.observe(el); });

